SELECT j.*, u.name AS user_name FROM device_import_jobs j
LEFT JOIN users u ON j.user_id = u.id
WHERE j.id = #{id} AND j.customer_id = #{customerId}

SELECT j.*, u.name AS user_name FROM device_export_jobs j
LEFT JOIN users u ON j.user_id = u.id
WHERE j.id = #{id} AND j.customer_id = #{customerId}
